// File: /app/project/src/data_sources/legacy_source.rs
// Purpose: Implement LegacyStreamSource wrapping existing Kafka logic

//! Legacy Stream Source Implementation
//!
//! This module wraps the original Kafka-based data ingestion logic in the
//! DataSource trait interface, enabling backward compatibility while
//! supporting the new abstraction layer.

use std::pin::Pin;
use std::sync::Arc;
use std::time::Duration;

use anyhow::{Context, Result};
use async_trait::async_trait;
use futures::{Stream, StreamExt};
use rdkafka::consumer::{Consumer, StreamConsumer};
use rdkafka::message::{BorrowedMessage, Message};
use rdkafka::ClientConfig;
use serde::{Deserialize, Serialize};
use tracing::{error, info, warn};

use super::{DataSource, SourceConfig};

/// The original Kafka-based data source implementation.
///
/// This struct encapsulates all the legacy connection and streaming logic
/// that was previously spread across module_79 and module_41, providing
/// a unified interface through the DataSource trait.
pub struct LegacyStreamSource {
    /// SASL username for Kafka authentication
    sasl_username: Option<String>,
    /// SASL password for Kafka authentication
    sasl_password: Option<String>,
    /// Security protocol (PLAINTEXT, SSL, SASL_SSL, etc.)
    security_protocol: String,
}

impl Default for LegacyStreamSource {
    fn default() -> Self {
        Self {
            sasl_username: None,
            sasl_password: None,
            security_protocol: "PLAINTEXT".to_string(),
        }
    }
}

impl LegacyStreamSource {
    /// Create a new LegacyStreamSource with default settings.
    pub fn new() -> Self {
        Self::default()
    }

    /// Configure SASL authentication.
    pub fn with_sasl_auth(
        mut self,
        username: impl Into<String>,
        password: impl Into<String>,
    ) -> Self {
        self.sasl_username = Some(username.into());
        self.sasl_password = Some(password.into());
        self.security_protocol = "SASL_SSL".to_string();
        self
    }

    /// Set the security protocol.
    pub fn with_security_protocol(mut self, protocol: impl Into<String>) -> Self {
        self.security_protocol = protocol.into();
        self
    }

    /// Build a Kafka StreamConsumer from the provided configuration.
    fn build_consumer(&self, config: &SourceConfig) -> Result<StreamConsumer> {
        let mut client_config = ClientConfig::new();

        client_config
            .set("bootstrap.servers", &config.endpoint)
            .set("group.id", config.consumer_group.as_deref().unwrap_or("chirp-pulse"))
            .set("enable.partition.eof", "false")
            .set("session.timeout.ms", "6000")
            .set("enable.auto.commit", "false")
            .set("enable.auto.offset.store", "false")
            .set("auto.offset.reset", "earliest")
            .set("security.protocol", &self.security_protocol);

        if let (Some(username), Some(password)) = (&self.sasl_username, &self.sasl_password) {
            client_config
                .set("sasl.mechanism", "SCRAM-SHA-512")
                .set("sasl.username", username)
                .set("sasl.password", password);
        }

        let consumer: StreamConsumer = client_config
            .create()
            .context("Failed to create Kafka consumer")?;

        if let Some(topic) = &config.topic {
            consumer.subscribe(&[topic])?;
        }

        info!(
            source_id = %config.source_id,
            endpoint = %config.endpoint,
            topic = ?config.topic,
            "LegacyStreamSource consumer created"
        );

        Ok(consumer)
    }
}

#[async_trait]
impl DataSource for LegacyStreamSource {
    fn name(&self) -> &'static str {
        "legacy_kafka"
    }

    async fn stream(
        &self,
        config: &SourceConfig,
    ) -> Pin<Box<dyn Stream<Item = Result<serde_json::Value, anyhow::Error>> + Send>> {
        // Build the consumer
        let consumer = match self.build_consumer(config) {
            Ok(c) => Arc::new(c),
            Err(e) => {
                error!(error = %e, "Failed to build Kafka consumer");
                return Box::pin(futures::stream::once(async move {
                    Err(anyhow::anyhow!("Failed to create consumer: {}", e))
                }));
            }
        };

        // Create an async stream from the Kafka consumer
        let stream = async_stream::stream! {
            let consumer = consumer.clone();
            let mut message_stream = consumer.stream();

            while let Some(result) = message_stream.next().await {
                match result {
                    Ok(borrowed_msg) => {
                        match Self::deserialize_message(&borrowed_msg) {
                            Ok(value) => yield Ok(value),
                            Err(e) => {
                                warn!(error = %e, "Failed to deserialize message");
                                yield Err(e);
                            }
                        }
                    }
                    Err(e) => {
                        error!(error = %e, "Kafka consumer error");
                        yield Err(anyhow::anyhow!("Kafka error: {}", e));
                    }
                }
            }
        };

        Box::pin(stream)
    }

    async fn health_check(&self, config: &SourceConfig) -> Result<(), anyhow::Error> {
        let consumer = self.build_consumer(config)?;
        // Try to fetch metadata to verify connection
        let timeout = Duration::from_millis(config.timeout_ms);
        consumer
            .fetch_metadata(config.topic.as_deref(), timeout)
            .context("Failed to fetch Kafka metadata")?;
        Ok(())
    }
}

impl LegacyStreamSource {
    /// Deserialize a Kafka message into a JSON Value.
    fn deserialize_message(msg: &BorrowedMessage<'_>) -> Result<serde_json::Value, anyhow::Error> {
        let payload = msg
            .payload()
            .ok_or_else(|| anyhow::anyhow!("Message has no payload"))?;

        serde_json::from_slice(payload)
            .context("Failed to deserialize message as JSON")
    }
}

