   172→            /// Ingests a batch of events, runs them through the configured
   173→            /// enrichers in *parallel*, and returns the resulting stream.
   174→            pub async fn process_batch<I>(
   175→                &self,
   176→                events: I,
   177→            ) -> Result<Vec<EnrichedEvent>, ChirpError>
   178→            where
   179→                I: IntoIterator<Item = Event>,
   180→            {
   181→                let start = Instant::now();
   182→                // Fan-out: each event processed by all enrichers concurrently
   183→                let futures: FuturesUnordered<_> = events
   184→                    .into_iter()
   185→                    .map(|evt| {
   186→                        let enrichers = self.enrichers.clone();
   187→                        tokio::spawn(async move {
   188→                            // Serial enrichment (replace with DAG in prod)
   189→                            let mut intermediate = evt;
   190→                            let mut all_enrichments = std::collections::HashMap::new();
   191→                            for enricher in enrichers {
   192→                                let enriched = enricher.enrich(intermediate).await?;
   193→                                intermediate = enriched.event.clone();
   194→                                all_enrichments.extend(enriched.enrichments);
   195→                            }
   196→                            Ok::<_, ChirpError>(super::models::EnrichedEvent {
   197→                                event: intermediate,
   198→                                enrichments: all_enrichments,
   199→                            })
   200→                        })
   201→                    })
   202→                    .collect();
   203→
   204→                let mut out = Vec::new();
   205→                for fut in futures {
   206→                    // Enforce global end-to-end latency budget
   207→                    let enriched = timeout(self.latency_budget, fut)
   208→                        .await
   209→                        .map_err(|_| ChirpError::Timeout)??;
   210→                    out.push(enriched);
   211→                }
   212→                tracing::info!(
   213→                    "Processed {} events in {:?}",
   214→                    out.len(),
   215→                    start.elapsed()
   216→                );
   217→                Ok(out)
   218→            }
   219→        }
