     2→//! Integration tests for utility components that power ChirpPulse’s
     3→//! streaming/analytics internals.  Although these helpers live in
     4→//! `chirp_pulse::utils`, re-implementations are provided here so the
     5→//! tests are completely self-contained and compile in isolation.  In the
     6→//! real project you would `use chirp_pulse::utils::*` instead.
     7→//!
     8→//! The utilities covered:
     9→//! 1. WeightedMovingAverage – constant-time sliding window average
    10→//! 2. RateLimitedExecutor     – client-side rate-limiter for burst control
    11→//! 3. retry_async             – exponential back-off with jitter
    12→//!
    13→//! The tests exercise determinism, concurrency safety, and boundary
    14→//! conditions (overflow, zero-division, etc.).
    15→
    16→use anyhow::{anyhow, bail, Result};
    17→use rand::{rngs::StdRng, Rng, SeedableRng};
    18→use std::{
    19→    collections::VecDeque,
    20→    sync::{Arc, Mutex},
    21→    time::{Duration, Instant},
    22→};
    23→use tokio::{
    24→    sync::Semaphore,
    25→    task::JoinHandle,
    26→    time::{sleep, timeout},
    27→};
    28→
    29→/// ------------------------------------------------------------------------------------------------
    30→/// WeightedMovingAverage
    31→/// ------------------------------------------------------------------------------------------------
    32→
    33→#[derive(Debug)]
    34→struct WeightedMovingAverage {
    35→    /// Maximum number of samples to include in the window
    36→    window: usize,
    37→    /// (value, weight) pairs in order of insertion
    38→    values: VecDeque<(f64, f64)>,
    39→    /// Cached sum(value * weight) for O(1) updates
    40→    sum_weighted: f64,
    41→    /// Cached sum(weight) for O(1) updates
    42→    sum_weights: f64,
    43→}
    44→
    45→impl WeightedMovingAverage {
    46→    fn new(window: usize) -> Self {
    47→        assert!(window > 0, "window must be greater than zero");
    48→        Self {
    49→            window,
    50→            values: VecDeque::with_capacity(window),
    51→            sum_weighted: 0.0,
    52→            sum_weights: 0.0,
    53→        }
    54→    }
    55→
    56→    /// Inserts a (value, weight) pair into the window.  If the window is
    57→    /// full, the oldest entry is evicted.
    58→    fn insert(&mut self, value: f64, weight: f64) {
    59→        if weight <= 0.0 {
    60→            // We tolerate zero‐weight samples (ignored) but negative
    61→            // weights would break the math.
    62→            panic!("weight must be positive");
    63→        }
    64→
    65→        // Push new sample
    66→        self.values.push_back((value, weight));
    67→        self.sum_weighted += value * weight;
    68→        self.sum_weights += weight;
    69→
    70→        // Evict if over capacity
    71→        if self.values.len() > self.window {
    72→            if let Some((old_val, old_w)) = self.values.pop_front() {
    73→                self.sum_weighted -= old_val * old_w;
    74→                self.sum_weights -= old_w;
    75→            }
    76→        }
    77→    }
    78→
    79→    fn average(&self) -> Option<f64> {
    80→        if self.sum_weights == 0.0 {
    81→            None
    82→        } else {
    83→            Some(self.sum_weighted / self.sum_weights)
    84→        }
    85→    }
    86→
    87→    fn len(&self) -> usize {
    88→        self.values.len()
    89→    }
    90→
    91→    fn is_empty(&self) -> bool {
    92→        self.values.is_empty()
    93→    }
    94→}
