    96→/// ------------------------------------------------------------------------------------------------
    97→/// RateLimitedExecutor
    98→/// ------------------------------------------------------------------------------------------------
    99→
   100→/// A simple, thread-safe token bucket that allows `capacity` “permits”
   101→/// every `interval`.  Tasks acquire a permit before running; if none are
   102→/// available they wait until the next refill.
   103→#[derive(Debug)]
   104→struct RateLimitedExecutor {
   105→    capacity: usize,
   106→    interval: Duration,
   107→    /// Timestamps of used permits; size <= capacity
   108→    permits: Mutex<VecDeque<Instant>>,
   109→}
   110→
   111→impl RateLimitedExecutor {
   112→    fn new(capacity: usize, interval: Duration) -> Self {
   113→        assert!(capacity > 0, "capacity must be > 0");
   114→        Self {
   115→            capacity,
   116→            interval,
   117→            permits: Mutex::new(VecDeque::with_capacity(capacity)),
   118→        }
   119→    }
   120→
   121→    /// Runs the future once a permit is available.  The executor itself
   122→    /// does not spawn; callers may `tokio::spawn` if needed.
   123→    async fn execute<F, T>(&self, fut: F) -> T
   124→    where
   125→        F: std::future::Future<Output = T>,
   126→    {
   127→        loop {
   128→            let mut guard = self.permits.lock().unwrap();
   129→
   130→            // Remove expired permits
   131→            let now = Instant::now();
   132→            while let Some(&front) = guard.front() {
   133→                if now.duration_since(front) >= self.interval {
   134→                    guard.pop_front();
   135→                } else {
   136→                    break;
   137→                }
   138→            }
   139→
   140→            if guard.len() < self.capacity {
   141→                // Acquire token
   142→                guard.push_back(now);
   143→                drop(guard);
   144→                break fut.await;
   145→            }
   146→
   147→            // No permits.  Figure out when the next one expires.
   148→            let wait_for = self
   149→                .interval
   150→                .checked_sub(now.duration_since(*guard.front().unwrap()))
   151→                .unwrap_or(Duration::from_millis(1));
   152→
   153→            drop(guard); // Release lock before sleeping
   154→            sleep(wait_for).await;
   155→        }
   156→    }
   157→}
