   159→/// ------------------------------------------------------------------------------------------------
   160→/// retry_async – exponential back-off with jitter
   161→/// ------------------------------------------------------------------------------------------------
   162→
   163→/// Configuration options for `retry_async`.
   164→#[derive(Clone, Copy, Debug)]
   165→struct RetryConfig {
   166→    max_retries: usize,
   167→    base_delay: Duration,
   168→    max_delay: Duration,
   169→}
   170→
   171→/// Retries an async operation until it succeeds (Ok) or the max retry
   172→/// count is reached.  Uses decorrelated jitter to avoid thundering herd.
   173→async fn retry_async<F, Fut, T>(cfg: RetryConfig, mut factory: F) -> Result<T>
   174→where
   175→    F: FnMut(usize) -> Fut,
   176→    Fut: std::future::Future<Output = Result<T>>,
   177→{
   178→    let mut attempt = 0;
   179→    let rng_seed = 0xDEADBEEF; // deterministic for tests
   180→    let mut rng = StdRng::seed_from_u64(rng_seed);
   181→
   182→    loop {
   183→        match factory(attempt).await {
   184→            Ok(v) => return Ok(v),
   185→            Err(e) if attempt < cfg.max_retries => {
   186→                attempt += 1;
   187→
   188→                // decorrelated jitter algorithm
   189→                let exp_delay = cfg.base_delay * (1u32 << attempt as u32);
   190→                let upper = std::cmp::min(exp_delay, cfg.max_delay);
   191→                let sleep_for = Duration::from_millis(rng.gen_range(
   192→                    cfg.base_delay.as_millis() as u64,
   193→                    upper.as_millis() as u64 + 1,
   194→                ));
   195→                sleep(sleep_for).await;
   196→
   197→                // Continue retrying
   198→                tracing::warn!(
   199→                    attempt,
   200→                    "retrying after error: {e:?}, sleeping for {:?}",
   201→                    sleep_for
   202→                );
   203→            }
   204→            Err(e) => {
   205→                bail!("retry_async: exhausted all attempts: {e}");
   206→            }
   207→        }
   208→    }
   209→}
