   215→#[test]
   216→fn weighted_moving_average_basic_math() {
   217→    let mut wma = WeightedMovingAverage::new(3);
   218→
   219→    assert!(wma.average().is_none());
   220→    wma.insert(10.0, 1.0); // average = 10
   221→    assert_eq!(wma.average().unwrap(), 10.0);
   222→
   223→    wma.insert(20.0, 1.0); // average = 15
   224→    assert_eq!(wma.average().unwrap(), 15.0);
   225→
   226→    wma.insert(30.0, 2.0); // weighted (10*1 + 20*1 + 30*2) / 4 = 22.5
   227→    assert_eq!(wma.average().unwrap(), 22.5);
   228→
   229→    // This insertion evicts the first sample (window = 3)
   230→    wma.insert(0.0, 1.0); // (20*1 + 30*2 + 0*1) / 4 = 20
   231→    assert_eq!(wma.average().unwrap(), 20.0);
   232→    assert_eq!(wma.len(), 3);
   233→}
