   246→#[tokio::test(flavor = "multi_thread", worker_threads = 4)]
   247→async fn rate_limiter_blocks_until_permit_available() {
   248→    let rl = Arc::new(RateLimitedExecutor::new(2, Duration::from_millis(100)));
   249→
   250→    let started = Instant::now();
   251→    let mut handles: Vec<JoinHandle<Instant>> = vec![];
