   269→    // First two should execute immediately (< 20 ms)
   270→    assert!(timestamps[1].duration_since(started) < Duration::from_millis(20));
   271→
   272→    // Next two should be >= 100 ms after start (due to rate limit)
   273→    for ts in &timestamps[2..] {
   274→        assert!(ts.duration_since(started) >= Duration::from_millis(100));
