//! src/data_sources/mod.rs
//!
//! Data Source Abstraction Layer for ChirpPulse
//!
//! This module defines the `DataSource` trait, which provides a uniform interface
//! for connecting to various data sources and yielding streams of raw data objects.
//! This abstraction enables the ChirpPulse system to support multiple data providers
//! (e.g., Twitter, Reddit, Mastodon) without tight coupling in the core processing
//! pipeline.
//!
//! The main components:
//!   * `DataSource` trait - The core abstraction for any data source
//!   * `SourceConfig` - Configuration parameters for connecting to a source
//!   * `legacy_source` module - The original streaming implementation wrapped in this abstraction

pub mod legacy_source;

use std::pin::Pin;

use async_trait::async_trait;
use futures::Stream;
use serde::{Deserialize, Serialize};

/// Configuration parameters for connecting to a data source.
///
/// This struct captures common settings needed to establish a connection
/// to various social media streaming APIs or other data providers.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SourceConfig {
    /// Unique identifier for the data source (e.g., "twitter", "reddit")
    pub source_id: String,

    /// API endpoint or broker address
    pub endpoint: String,

    /// Authentication credentials (typically an API key or token)
    pub api_key: Option<String>,

    /// Consumer group or subscription identifier for distributed processing
    pub consumer_group: Option<String>,

    /// Topic or stream name to subscribe to
    pub topic: Option<String>,

    /// Maximum number of items to buffer before applying backpressure
    pub buffer_size: usize,

    /// Connection timeout in milliseconds
    pub timeout_ms: u64,

    /// Additional source-specific configuration as key-value pairs
    pub extra: std::collections::HashMap<String, serde_json::Value>,
}

impl Default for SourceConfig {
    fn default() -> Self {
        Self {
            source_id: "default".to_string(),
            endpoint: "localhost:9092".to_string(),
            api_key: None,
            consumer_group: Some("chirp-pulse-consumer".to_string()),
            topic: Some("social_raw".to_string()),
            buffer_size: 1024,
            timeout_ms: 5000,
            extra: std::collections::HashMap::new(),
        }
    }
}

impl SourceConfig {
    /// Create a new SourceConfig with the given source ID and endpoint.
    pub fn new(source_id: impl Into<String>, endpoint: impl Into<String>) -> Self {
        Self {
            source_id: source_id.into(),
            endpoint: endpoint.into(),
            ..Default::default()
        }
    }

    /// Set the API key for authentication.
    pub fn with_api_key(mut self, api_key: impl Into<String>) -> Self {
        self.api_key = Some(api_key.into());
        self
    }

    /// Set the consumer group for distributed processing.
    pub fn with_consumer_group(mut self, group: impl Into<String>) -> Self {
        self.consumer_group = Some(group.into());
        self
    }

    /// Set the topic or stream name.
    pub fn with_topic(mut self, topic: impl Into<String>) -> Self {
        self.topic = Some(topic.into());
        self
    }

    /// Set the buffer size for backpressure control.
    pub fn with_buffer_size(mut self, size: usize) -> Self {
        self.buffer_size = size;
        self
    }

    /// Set the connection timeout.
    pub fn with_timeout_ms(mut self, timeout: u64) -> Self {
        self.timeout_ms = timeout;
        self
    }
}

/// The core trait for abstracting data sources in the ChirpPulse system.
///
/// Implementations of this trait connect to various data providers and
/// yield a stream of raw JSON data objects. This allows the processing
/// pipeline to remain agnostic of the specific data source being used.
///
/// # Example
///
/// ```rust,ignore
/// use chirp_pulse::data_sources::{DataSource, SourceConfig};
/// use futures::StreamExt;
///
/// async fn process_events(source: Box<dyn DataSource>) {
///     let config = SourceConfig::new("twitter", "api.twitter.com");
///     let mut stream = source.stream(&config).await;
///
///     while let Some(result) = stream.next().await {
///         match result {
///             Ok(event) => println!("Received: {:?}", event),
///             Err(e) => eprintln!("Error: {}", e),
///         }
///     }
/// }
/// ```
#[async_trait]
pub trait DataSource: Send + Sync {
    /// Returns the name of this data source for logging and metrics.
    fn name(&self) -> &'static str;

    /// Connects to the data source and returns a stream of raw data objects.
    ///
    /// # Arguments
    ///
    /// * `config` - Configuration parameters for connecting to the source
    ///
    /// # Returns
    ///
    /// A pinned, boxed, sendable stream that yields `Result<serde_json::Value, anyhow::Error>`.
    /// Each successful item is a JSON value representing a raw social event.
    /// Errors indicate connection issues, parsing failures, or other I/O problems.
    async fn stream(
        &self,
        config: &SourceConfig,
    ) -> Pin<Box<dyn Stream<Item = Result<serde_json::Value, anyhow::Error>> + Send>>;

    /// Checks if the data source is currently healthy and able to accept connections.
    ///
    /// This method can be used for health checks and circuit breaker patterns.
    async fn health_check(&self, config: &SourceConfig) -> Result<(), anyhow::Error> {
        // Default implementation: assume healthy if stream method doesn't fail immediately
        Ok(())
    }
}

// Re-export the legacy source implementation for convenience
pub use legacy_source::LegacyStreamSource;

#[cfg(test)]
mod tests {
    use super::*;
    use futures::StreamExt;

    /// A mock data source for testing purposes.
    pub struct MockDataSource {
        events: Vec<serde_json::Value>,
    }

    impl MockDataSource {
        pub fn new(events: Vec<serde_json::Value>) -> Self {
            Self { events }
        }
    }

    #[async_trait]
    impl DataSource for MockDataSource {
        fn name(&self) -> &'static str {
            "mock"
        }

        async fn stream(
            &self,
            _config: &SourceConfig,
        ) -> Pin<Box<dyn Stream<Item = Result<serde_json::Value, anyhow::Error>> + Send>> {
            let events = self.events.clone();
            Box::pin(futures::stream::iter(events.into_iter().map(Ok)))
        }
    }

    #[tokio::test]
    async fn test_source_config_builder() {
        let config = SourceConfig::new("twitter", "api.twitter.com")
            .with_api_key("secret-key")
            .with_topic("tweets")
            .with_buffer_size(2048);

        assert_eq!(config.source_id, "twitter");
        assert_eq!(config.endpoint, "api.twitter.com");
        assert_eq!(config.api_key, Some("secret-key".to_string()));
        assert_eq!(config.topic, Some("tweets".to_string()));
        assert_eq!(config.buffer_size, 2048);
    }

    #[tokio::test]
    async fn test_mock_data_source_streams_events() {
        let events = vec![
            serde_json::json!({"id": "1", "text": "Hello"}),
            serde_json::json!({"id": "2", "text": "World"}),
        ];
        let source = MockDataSource::new(events);
        let config = SourceConfig::default();

        let mut stream = source.stream(&config).await;
        let first = stream.next().await.unwrap().unwrap();
        assert_eq!(first["id"], "1");

        let second = stream.next().await.unwrap().unwrap();
        assert_eq!(second["id"], "2");

        assert!(stream.next().await.is_none());
    }
}
