/// Convert a borrowed Kafka message to `SocialEvent`.
fn deserialize_event(msg: &BorrowedMessage<'_>) -> Result<SocialEvent, serde_json::Error> {
    serde_json::from_slice::<SocialEvent>(msg.payload().unwrap_or_default())
