/// Run QC service until Ctrl-C/TERM
pub async fn run(data_source: Box<dyn DataSource>) -> Result<()> {
    // --- Logging / tracing
    tracing_subscriber::fmt::init();

    let cfg = Config::from_env();
    info!("Launching QC microservice with config: {:?}", cfg);

    // Metrics
    let metrics = Arc::new(Metrics::new());

    // Kafka producer (still needed for output)
    let producer = build_producer(&cfg)?;

    // Quality controller with injected data source
    let qc = Arc::new(QualityController::new(
        cfg.clone(),
        producer,
        metrics.clone(),
        data_source,
    ));

    // Graceful shutdown orchestration
    let shutdown = Arc::new(Notify::new());
    let shutdown_signal = shutdown.clone();

    // Spawn Prometheus exporter
    let metric_handle = {
        let m = metrics.clone();
        tokio::spawn(async move {
            if let Err(e) = m.serve().await {
                error!("Metrics exporter stopped: {e}");
            }
        })
    };

    // Spawn data processing loop using data source
    let qc_clone = qc.clone();
    let kafka_handle = tokio::spawn(async move {
        if let Err(e) = qc_clone.run_with_source().await {
            error!("QC processing error: {e}");
        }
    });

    // Listen for SIGINT / SIGTERM
    tokio::spawn(async move {
        let mut sig_int = signal(SignalKind::interrupt()).unwrap();
        let mut sig_term = signal(SignalKind::terminate()).unwrap();
        tokio::select! {
            _ = sig_int.recv() => {
                info!("Received SIGINT, shutting down");
            }
            _ = sig_term.recv() => {
                info!("Received SIGTERM, shutting down");
            }
        }
        shutdown_signal.notify_waiters();
    });

    // Wait until shutdown notified
    shutdown.notified().await;
    info!("Stopping QC microservice…");

    kafka_handle.abort();
    metric_handle.abort();

    Ok(())
}

