// Purpose: Define the DataSource trait abstraction

//! Data Source Abstraction Layer for ChirpPulse
//!
//! This module defines the `DataSource` trait, which provides a uniform interface
//! for connecting to various data sources and yielding streams of raw data objects.
//! This abstraction enables the ChirpPulse system to support multiple data providers
//! (e.g., Twitter, Reddit, Mastodon) without tight coupling in the core processing
//! pipeline.

pub mod legacy_source;

use std::pin::Pin;

use async_trait::async_trait;
use futures::Stream;
use serde::{Deserialize, Serialize};

/// Configuration parameters for connecting to a data source.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SourceConfig {
    /// Unique identifier for the data source (e.g., "twitter", "reddit", "kafka")
    pub source_id: String,
    /// API endpoint or broker address
    pub endpoint: String,
    /// Authentication credentials (API key or token)
    pub api_key: Option<String>,
    /// Consumer group for distributed processing
    pub consumer_group: Option<String>,
    /// Topic or stream name to subscribe to
    pub topic: Option<String>,
    /// Maximum buffer size before backpressure
    pub buffer_size: usize,
    /// Connection timeout in milliseconds
    pub timeout_ms: u64,
    /// Additional source-specific configuration
    pub extra: std::collections::HashMap<String, serde_json::Value>,
}

impl Default for SourceConfig {
    fn default() -> Self {
        Self {
            source_id: "default".to_string(),
            endpoint: "localhost:9092".to_string(),
            api_key: None,
            consumer_group: Some("chirp-pulse-consumer".to_string()),
            topic: Some("social_raw".to_string()),
            buffer_size: 1024,
            timeout_ms: 5000,
            extra: std::collections::HashMap::new(),
        }
    }
}

impl SourceConfig {
    pub fn new(source_id: impl Into<String>, endpoint: impl Into<String>) -> Self {
        Self {
            source_id: source_id.into(),
            endpoint: endpoint.into(),
            ..Default::default()
        }
    }

    pub fn with_api_key(mut self, api_key: impl Into<String>) -> Self {
        self.api_key = Some(api_key.into());
        self
    }

    pub fn with_consumer_group(mut self, group: impl Into<String>) -> Self {
        self.consumer_group = Some(group.into());
        self
    }

    pub fn with_topic(mut self, topic: impl Into<String>) -> Self {
        self.topic = Some(topic.into());
        self
    }

    pub fn with_buffer_size(mut self, size: usize) -> Self {
        self.buffer_size = size;
        self
    }

    pub fn with_timeout_ms(mut self, timeout: u64) -> Self {
        self.timeout_ms = timeout;
        self
    }
}

/// The core trait for abstracting data sources in the ChirpPulse system.
///
/// Implementations of this trait connect to various data providers and
/// yield a stream of raw JSON data objects. This allows the processing
/// pipeline to remain agnostic of the specific data source being used.
#[async_trait]
pub trait DataSource: Send + Sync {
    /// Returns the name of this data source for logging and metrics.
    fn name(&self) -> &'static str;

    /// Connects to the data source and returns a stream of raw data objects.
    ///
    /// # Arguments
    /// * `config` - Configuration parameters for connecting to the source
    ///
    /// # Returns
    /// A pinned, boxed, sendable stream that yields `Result<serde_json::Value, anyhow::Error>`.
    async fn stream(
        &self,
        config: &SourceConfig,
    ) -> Pin<Box<dyn Stream<Item = Result<serde_json::Value, anyhow::Error>> + Send>>;

    /// Health check for the data source connection.
    async fn health_check(&self, config: &SourceConfig) -> Result<(), anyhow::Error> {
        Ok(())
    }
}

