    pub async fn run_with_source(&self) -> Result<()> {
        let source_config = SourceConfig::new(&self.cfg.group_id, &self.cfg.brokers)
            .with_topic(&self.cfg.input_topic)
            .with_consumer_group(&self.cfg.group_id);

        let mut stream = self.data_source.stream(&source_config).await;

        while let Some(result) = stream.next().await {
            match result {
                Ok(json_value) => {
